steps.script:
var uid = ""
for id in GameState.state["units"]:
	if GameState.state["units"][id].get("owner", 0) == 1:
		uid = id
		break
if uid == "":
	return "NO_UNIT"
var u = GameState.state["units"][uid]
var meta = u.get("meta", {})
var abilities = meta.get("abilities", [])
abilities.append({"name": "Redeploy"})
meta["abilities"] = abilities
u["meta"] = meta
GameState.set_active_player(1)
PhaseManager.transition_to_phase(2)
return true

var fp = PhaseManager.get_current_phase_instance()
var total = 0
for p in fp.redeploy_units_pending:
	total += fp.redeploy_units_pending[p].size()
return total

var fp = PhaseManager.get_current_phase_instance()
var v = fp.validate_action({"type": "END_REDEPLOYMENT_PHASE", "player": 1})
return v.get("valid", false)

var fp = PhaseManager.get_current_phase_instance()
var r = fp.execute_action({"type": "END_REDEPLOYMENT_PHASE", "player": 1})
return r.get("success", false)
